// Универсальный sessions sync для всех агентов.
// Body: { action, token, agent, session_id?, name?, sort_order? }
//   action  = 'list' | 'upsert' | 'delete'
//   agent   =  'chat' | 'sql' | 'rag' | 'math' | 'prompt' | 'plane' | ...
const body = $input.first().json.body || {};
const action = String(body.action || 'list').trim();
if (!['list','upsert','delete'].includes(action)) {
  return [{ json: { valid: 0, error: 'Неизвестный action' } }];
}
const token = String(body.token || '').trim();
if (!/^[a-f0-9]{64}$/.test(token)) {
  return [{ json: { valid: 0, error: 'unauthorized', auth_required: true } }];
}
const agent = String(body.agent || '').trim().toLowerCase();
if (!agent || !/^[a-z0-9_-]{1,32}$/.test(agent)) {
  return [{ json: { valid: 0, error: 'agent обязателен (1-32 alphanum)' } }];
}
const out = { valid: 1, action, token, agent };
if (action === 'upsert' || action === 'delete') {
  const sid = String(body.session_id || '').trim();
  if (!sid || !/^[a-zA-Z0-9_-]{1,128}$/.test(sid)) {
    return [{ json: { valid: 0, error: 'session_id обязательно (alphanum_-, max 128)' } }];
  }
  out.session_id = sid;
  if (action === 'upsert') {
    const name = String(body.name || '').trim().slice(0, 200);
    if (!name) return [{ json: { valid: 0, error: 'name обязательно' } }];
    out.name = name;
    const so = parseInt(body.sort_order, 10);
    out.sort_order = Number.isInteger(so) ? so : 0;
  }
}
return [{ json: out }];

